function processData() {
  const inputArray = $input.all().filter(item => item.json);

  return inputArray.map(entry => {
    const item = entry.json;
    const data = item.data || {};

    // 1. 先获取基础名称 (用于默认情况)
    let procedure_name =
      (data.unblind_name && String(data.unblind_name).trim()) ||
      (data.unbind_name && String(data.unbind_name).trim()) ||
      (data.data_old && data.data_old.procedure_name && String(data.data_old.procedure_name).trim()) ||
      '';

    // ============================================================
    // 2. 【核心逻辑修改】
    //    条件1：data_old 里有 Detail
    //    条件2：内部名称必须包含 "气压计" (从而排除 ATE测试、MIC测试等)
    // ============================================================
    if (data.data_old && data.data_old.Detail) {

      // 获取内部工序名称 (优先取 Station，比如 "半成品气压计校准")
      let innerName = "";
      if (data.data_old.Station) {
          innerName = String(data.data_old.Station).trim();
      } else if (data.data_old.procedure_name) {
          innerName = String(data.data_old.procedure_name).trim();
      }

      // 只有当内部名称明确包含 "气压计" 时，才加上 "报告解绑"
      // 这里的 .includes("气压计") 完美排除了 "ATE测试"
      if (innerName && innerName.includes("气压计")) {
          procedure_name = innerName + "报告解绑";
      }
    }

    // 3. 获取 binding_data
    let binding_data = '';
    if (data.data_old && typeof data.data_old.bind_id !== 'undefined') {
      binding_data = data.data_old.bind_id || '';
    }

    // 4. 获取 machine_data_id_old
    let machine_data_id_old = data.machine_data_id_old !== undefined ? String(data.machine_data_id_old) : '';

    return {
      procedure_name: procedure_name,
      createtime: item.createtime || "",
      machine_data_id: item.machine_data_id != null ? String(item.machine_data_id) : "未知",
      binding_action: "2",
      binding_data: binding_data,
      procedure_detail_id: item.procedure_detail_id,
      machine_data_id_old: machine_data_id_old
    };
  });
}

const result = processData();
return result;

function processData() {
  // 获取输入数据
  const inputArray = $input.all().filter(item => item.json);

  // 使用map函数处理每个元素
  const outputArray = inputArray.map(entry => {
    const item = entry.json; // 提取json字段中的内容

    // 直接从 item 中获取 procedure_name
    let procedureName = item.procedure_name || '';

    if (procedureName && !procedureName.includes('绑定')) {
      procedureName += '绑定';
    }

    return {
      procedure_name: procedureName,
      createtime: item.createtime,
      machine_data_id: item.machine_data_id.toString(),
      binding_action: "1",
      binding_data: item.data.bind_id || '',
      procedure_detail_id: item.procedure_detail_id,
      machine_data_id_old: ''
    };
  }).filter(entry => entry.binding_data !== ''); // 过滤掉 binding_data 为空的条目

  return outputArray;
}

// 调用并获取结果
return processData();

function normalizeProcedureName(procedureName) {
    // 去掉"绑定"和"解绑"，然后修剪字符串和去掉可能的多余符号
    return procedureName.replace(/(绑定|解绑|绑)/g, '').replace(/\\|"/g, '').trim();
}

function generateTransformedResponse(inputData) {
    const procedureMap = {};

    inputData.forEach(item => {
        // 使用标准化后的名称
        const procedureName = normalizeProcedureName(item.json.procedure_name);

        // 这里完全保留您原来的字段（没有加 binding_action）
        const currentEntry = {
            "procedure_name": procedureName,
            "createtime": item.json.createtime,
            "binding_data": item.json.binding_data
        };

        if (!procedureMap[procedureName] || new Date(item.json.createtime) > new Date(procedureMap[procedureName].createtime)) {
            // 记录最新的条目
            procedureMap[procedureName] = currentEntry;
        }
    });

    const bindingHistory = Object.values(procedureMap).map(entry => {
        if (entry.binding_action === "2") {
            // 如果是解绑操作，设置binding_data为空
            return {
                ...entry,
                binding_data: "",
                machine_data_id: ""
            };
        }
        return entry;
    });

    return {
        "code": "200",
        "binding_history": bindingHistory
    };
}

