const data = $input.all();

// 创建一个对象来存储最新记录的数据
let latestData = {};

// 遍历输入的数据列表
data.forEach(item => {
    const record = item.json; // 提取JSON记录
    let recordData;

    try {
        if (typeof record.data === "string") {
            recordData = JSON.parse(record.data);
        } else {
            console.warn("Data field is not a valid string:", record.data);
            return;
        }
    } catch (error) {
        console.error("Error parsing JSON:", error, "Data:", record.data);
        return;
    }

    let procName;
    let createtime;

    // 如果是解绑记录
    if (record.procedure_detail_id === 62) {
        procName = recordData.data_old.procedure_name;
        createtime = new Date(record.createtime).getTime();

        console.log(`Processing unbind: ${procName}, Time: ${createtime}`);

        // 在最新���绑记录时移除工序的所有记录
        const currentRecord = latestData[procName];
        if (!currentRecord || createtime > new Date(currentRecord.createtime).getTime()) {
            console.log(`Removing all records for: ${procName} due to unbind`);
            latestData[procName] = null; // 标记为移除
        }
    } else {
        // 处理绑定记录
        procName = record.procedure_name || recordData.procedure_name;
        createtime = new Date(record.createtime).getTime();

        console.log(`Processing bind: ${procName}, Time: ${createtime}`);

        // 更新绑定记录，但前提是尚未进行过解绑
        if (latestData[procName] !== null && (!latestData[procName] || createtime > new Date(latestData[procName].createtime).getTime())) {
            // 额外提取 bind_id
            const bindId = recordData.bind_id || recordData.data_old.bind_id || null;

            // 存储记录及其 bind_id
            latestData[procName] = { ...record, bind_id: bindId };
        }
    }
});

// 过滤掉所有标记为 null 的工序名称
const latestRecords = Object.values(latestData).filter(record => record !== null);

// 输出并返回最终记录列表
console.log("Latest records found:", latestRecords);
return latestRecords;

