function processData() {
  // 获取输入数据
  const inputArray = $input.all().filter(item => item.json);

  const outputArray = inputArray.map(entry => {
    const item = entry.json; 
    const itemData = item.data || {}; // 防止 data 为空报错

    // --- 核心修改 1：先获取 Detail ---
    // 如果 Detail 是 undefined, null 或 "", 这里都会得到 false
    const detailContent = itemData.Detail;

    // 如果没有 Detail 数据，直接返回 null，稍后统一过滤
    if (!detailContent) {
        return null;
    }

    // ---原本的工序名称处理逻辑---
    let procedureName = item.procedure_name || '';
    const reportProcedures = ["半成品气压计校准", "气压计校准"];

    if (reportProcedures.includes(procedureName)) {
        procedureName += '报告绑定'; 
    } 
    else if (procedureName && !procedureName.includes('绑定')) {
        procedureName += '绑定';
    }

    // ---组装返回对象---
    return {
      procedure_name: procedureName,
      createtime: item.createtime,
      machine_data_id: item.machine_data_id.toString(),
      binding_action: "1",
      binding_data: detailContent, // 使用上面获取的内容
      procedure_detail_id: item.procedure_detail_id,
      machine_data_id_old: ''
    };
  })
  // --- 核心修改 2：过滤掉所有为 null 的项 ---
  .filter(entry => entry !== null); 

  return outputArray;
}

return processData();

