let sqlData = [];
try {
  // 确保这里的节点名称和你画布上的名称完全一致
  sqlData = $("Execute a SQL query").all();
} catch (e) {
  // 如果SQL节点没运行或报错，这里保持为空数组
}

// 3. 合并数据并返回
