return webhookData.map((item, index) => {
  //以此获取对应的 SQL 数据行，如果没有对应行则给个空对象
  const sqlItem = sqlData[index] ? sqlData[index].json : {};

  // 获取 SQL 中的 retroid_id (如果 SQL 没查到数据，这里会是 undefined)
  const retroidId = sqlItem.retroid_id;

  return {
    json: {
      ...item.json,        // 保留 Webhook 的所有原始字段 (body, query, etc.)
      retroid_id: retroidId // 新增/追加 retroid_id 字段
    }
  };
});

